import 'dart:io'; import 'package:flutter/material.dart'; import '../../domain/entities/report.dart'; import 'evidence_image_grid.dart'; import 'report_reason_selector.dart';
class ReportForm extends StatelessWidget{final ReportReason reason; final ValueChanged<ReportReason> onReasonChanged; final TextEditingController descriptionController; final List<File> evidenceImages; final VoidCallback onAddImage; final ValueChanged<int> onRemoveImage; final bool isLoading; final VoidCallback onSubmit; const ReportForm({super.key,required this.reason,required this.onReasonChanged,required this.descriptionController,required this.evidenceImages,required this.onAddImage,required this.onRemoveImage,required this.isLoading,required this.onSubmit}); @override Widget build(BuildContext context)=>ListView(padding:const EdgeInsets.all(16),children:[ReportReasonSelector(selectedReason:reason,onChanged:onReasonChanged),const SizedBox(height:12),TextField(controller:descriptionController,minLines:4,maxLines:8,decoration:const InputDecoration(labelText:'Description')),const SizedBox(height:12),EvidenceImageGrid(images:evidenceImages,onAddImage:onAddImage,onRemoveLocalImage:onRemoveImage,isUploading:isLoading),const SizedBox(height:20),FilledButton.icon(onPressed:isLoading?null:onSubmit,icon:const Icon(Icons.report),label:const Text('Submit Report'))]);}
